/**
 * @summary Get job market insights for a career
 */
export const getGetCareerInsightsUrl = (params: GetCareerInsightsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/insights?${stringifiedParams}`
    : `/api/insights`;
};

export const getCareerInsights = async (
  params: GetCareerInsightsParams,
  options?: RequestInit,
): Promise<CareerInsights> => {
  return customFetch<CareerInsights>(getGetCareerInsightsUrl(params), {
    ...options,
    method: "GET",
  });
};

